insert into public.questions (id, topic, source, q, opts, ans_idx, exp, category, category_icon, is_active)
values
(3538, 'Cardiovascular Scenarios', 'AI Practice Question', 'A patient''s ECG shows a saw-tooth pattern of atrial activity at a rate of about 300/min with a regular ventricular response of 150/min. This rhythm is most consistent with:', '["Atrial fibrillation", "Atrial flutter with 2:1 conduction", "Ventricular tachycardia", "Sinus tachycardia"]'::jsonb, 1, 'The classic ''saw-tooth'' flutter waves at ~300/min with a regular ventricular rate (commonly 150/min with 2:1 conduction) are characteristic of atrial flutter.', 'Cardiovascular', '🫀', true),
(3539, 'Cardiovascular Scenarios', 'AI Practice Question', 'A patient develops sudden cardiac arrest with an ECG showing chaotic, disorganised electrical activity and no discernible QRS complexes. This rhythm is:', '["Asystole", "Ventricular fibrillation, a shockable rhythm requiring immediate defibrillation", "First-degree heart block", "Sinus arrhythmia"]'::jsonb, 1, 'Chaotic, disorganised electrical activity with no organised QRS complexes is ventricular fibrillation, a shockable rhythm requiring immediate defibrillation as part of ACLS.', 'Cardiovascular', '🫀', true),
(3540, 'Cardiovascular Scenarios', 'AI Practice Question', 'During CPR, the recommended compression-to-ventilation ratio for a single rescuer performing adult CPR without an advanced airway is:', '["15:2", "30:2", "5:1", "Continuous compressions with no ventilation"]'::jsonb, 1, 'For a single rescuer without an advanced airway, the standard adult CPR ratio is 30 compressions to 2 rescue breaths.', 'Cardiovascular', '🫀', true),
(3541, 'Cardiovascular Scenarios', 'AI Practice Question', 'Once a patient is intubated during cardiac arrest, chest compressions and ventilations are given as:', '["Still synchronised at 30:2", "Continuous compressions at 100-120/min with asynchronous ventilations at about 10 breaths/min", "Compressions only, with no ventilation at all", "Ventilation only, with compressions paused"]'::jsonb, 1, 'Once an advanced airway is in place, compressions become continuous (not paused for breaths) while ventilations are delivered asynchronously at roughly 10/min.', 'Cardiovascular', '🫀', true),
(3542, 'Cardiovascular Scenarios', 'AI Practice Question', 'A patient has return of spontaneous circulation (ROSC) after cardiac arrest but remains comatose. The team considers targeted temperature management. The primary goal of this intervention is to:', '["Increase metabolic demand to speed recovery", "Reduce secondary neurological injury by lowering cerebral metabolic demand", "Prevent infection", "Increase heart rate"]'::jsonb, 1, 'Targeted temperature management after ROSC aims to reduce cerebral metabolic demand and limit secondary neurological injury following the ischaemic insult of cardiac arrest.', 'Cardiovascular', '🫀', true),
(3543, 'Cardiovascular', 'AI Practice Question', 'A first-degree heart block on ECG is characterised by:', '["Complete dissociation between P waves and QRS complexes", "A prolonged PR interval with every P wave still followed by a QRS complex", "Absent P waves entirely", "A widened QRS with no P waves"]'::jsonb, 1, 'First-degree heart block shows a prolonged PR interval (>0.20 seconds) but every atrial impulse still conducts to produce a QRS complex.', 'Cardiovascular', '🫀', true),
(3544, 'Cardiovascular', 'AI Practice Question', 'Third-degree (complete) heart block is characterised by:', '["A mildly prolonged PR interval with normal conduction", "Complete dissociation between atrial (P wave) and ventricular (QRS) activity, often requiring pacing", "Normal sinus rhythm", "Occasional dropped beats with a predictable pattern only"]'::jsonb, 1, 'Complete heart block shows total dissociation between atrial and ventricular activity, with the ventricles beating independently via an escape rhythm — often requiring pacemaker insertion.', 'Cardiovascular', '🫀', true),
(3545, 'Cardiovascular Scenarios', 'AI Practice Question', 'A patient is being weaned off an intra-aortic balloon pump (IABP). The nurse understands that weaning typically involves:', '["Abrupt discontinuation with no gradual process", "Gradually reducing the augmentation ratio (e.g. from 1:1 to 1:2 to 1:3) while monitoring haemodynamic tolerance", "Immediately removing the catheter with no monitoring", "Increasing the balloon inflation volume progressively"]'::jsonb, 1, 'IABP weaning is typically gradual, reducing the assist ratio stepwise while closely monitoring the patient''s haemodynamic tolerance before full discontinuation.', 'Cardiovascular', '🫀', true),
(3546, 'Cardiovascular Scenarios', 'AI Practice Question', 'A patient with congestive heart failure is taught to monitor for early signs of fluid overload at home. The nurse should advise the patient to primarily watch for:', '["Weight loss and decreased appetite", "Rapid weight gain (e.g. more than 1-2kg in a few days), increasing dyspnoea, and oedema", "Improved exercise tolerance", "Decreased urine output only, with no other symptom"]'::jsonb, 1, 'Rapid weight gain, worsening dyspnoea and increasing oedema are early warning signs of fluid overload/decompensating heart failure that patients are taught to monitor and report promptly.', 'Cardiovascular', '🫀', true),
(3547, 'Cardiovascular', 'AI Practice Question', 'The dicrotic notch seen on an arterial pressure waveform corresponds to:', '["Opening of the aortic valve", "Closure of the aortic valve", "Opening of the mitral valve", "Peak systolic pressure"]'::jsonb, 1, 'The dicrotic notch on the arterial waveform reflects closure of the aortic valve at the end of systole.', 'Cardiovascular', '🫀', true),
(3548, 'Respiratory Scenarios', 'AI Practice Question', 'A patient with ARDS on mechanical ventilation has a plateau pressure consistently above 30cmH2O. The nurse understands this is concerning because:', '["It indicates optimal lung compliance", "It increases the risk of ventilator-induced lung injury (barotrauma), and settings should be adjusted to keep plateau pressure below this threshold", "It has no clinical significance", "It indicates the patient is ready for extubation"]'::jsonb, 1, 'Sustained plateau pressures above 30cmH2O increase the risk of barotrauma/volutrauma in ARDS — lung-protective ventilation targets keeping plateau pressure below this threshold.', 'Respiratory', '🫁', true),
(3549, 'Respiratory Scenarios', 'AI Practice Question', 'A patient''s spontaneous breathing trial (SBT) is being assessed for extubation readiness. Signs suggesting the SBT has failed include:', '["Stable respiratory rate and oxygen saturation throughout", "Rising respiratory rate above 35/min, falling SpO2, and increasing work of breathing", "Calm, comfortable breathing pattern", "Normal heart rate and blood pressure throughout"]'::jsonb, 1, 'SBT failure is indicated by rising respiratory rate, desaturation, increased work of breathing, or haemodynamic instability, suggesting the patient is not yet ready for extubation.', 'Respiratory', '🫁', true),
(3550, 'Respiratory Scenarios', 'AI Practice Question', 'A patient is extubated successfully but develops increasing stridor and respiratory distress within an hour. The nurse should anticipate:', '["No specific concern, since extubation was successful", "Post-extubation laryngeal oedema/airway swelling, potentially requiring nebulised adrenaline, steroids, or reintubation", "Discharge planning", "No monitoring is needed for the next several hours"]'::jsonb, 1, 'Post-extubation stridor suggests laryngeal oedema — management may include nebulised adrenaline and steroids, with close monitoring and readiness for reintubation if it worsens.', 'Respiratory', '🫁', true),
(3551, 'Respiratory', 'AI Practice Question', 'The ''rapid shallow breathing index'' (RSBI), used to predict weaning success, is calculated as:', '["Respiratory rate divided by tidal volume (in litres)", "Heart rate divided by respiratory rate", "Tidal volume divided by respiratory rate", "Blood pressure divided by respiratory rate"]'::jsonb, 0, 'RSBI = respiratory rate (breaths/min) ÷ tidal volume (litres); a value below 105 generally predicts a higher likelihood of successful weaning.', 'Respiratory', '🫁', true),
(3552, 'Respiratory Scenarios', 'AI Practice Question', 'A patient''s ABG shows pH 7.32, PaCO2 50mmHg, HCO3 25mmol/L in the context of an acute severe asthma attack. The nurse should recognise this as particularly concerning because:', '["This is a normal finding for asthma", "A ''normalising'' or rising PaCO2 in a tiring asthmatic (previously hyperventilating with low PaCO2) suggests impending respiratory failure", "This indicates the patient is improving significantly", "No action is required"]'::jsonb, 1, 'In severe asthma, patients initially hyperventilate (low PaCO2); a rising or ''normalising'' PaCO2 signals fatigue and impending respiratory failure — a critical warning sign, not reassurance.', 'Respiratory', '🫁', true),
(3553, 'Respiratory Scenarios', 'AI Practice Question', 'A patient with a new tracheostomy accidentally has the tube dislodge within the first 72 hours (before a stable tract has formed). The nurse''s priority action is to:', '["Attempt to reinsert the tube blindly with force", "Call for immediate emergency airway assistance, as reinsertion in an immature tract can create a false passage", "Wait for the tract to heal before any action", "Simply cover the stoma with a dressing and observe"]'::jsonb, 1, 'In the first 72 hours, the tracheostomy tract is not yet mature — blind reinsertion risks creating a false passage. This is an airway emergency requiring urgent skilled assistance.', 'Respiratory', '🫁', true),
(3554, 'Respiratory', 'AI Practice Question', 'Auto-PEEP (intrinsic PEEP), sometimes seen in patients with severe airflow obstruction on a ventilator, occurs when:', '["The patient fully exhales before the next breath is delivered", "Incomplete exhalation traps air in the lungs before the next breath, causing progressive hyperinflation", "PEEP is set too low", "There is no relationship to ventilator settings"]'::jsonb, 1, 'Auto-PEEP occurs when the expiratory time is insufficient for complete exhalation (common in severe airflow obstruction), causing air trapping and progressive hyperinflation with each breath.', 'Respiratory', '🫁', true),
(3555, 'Respiratory Scenarios', 'AI Practice Question', 'A patient with severe asthma on the ventilator develops sudden hypotension and difficulty bagging. The nurse should consider disconnecting the patient from the ventilator briefly to allow full exhalation, since this presentation may reflect:', '["Normal ventilator function", "Severe auto-PEEP/breath stacking causing dynamic hyperinflation and reduced venous return", "An unrelated cardiac event only", "Improved lung compliance"]'::jsonb, 1, 'Severe dynamic hyperinflation from breath stacking/auto-PEEP can cause obstructive shock-like physiology (reduced venous return, hypotension) — a brief ventilator disconnect allows full exhalation and can rapidly improve haemodynamics.', 'Respiratory', '🫁', true),
(3556, 'Respiratory', 'AI Practice Question', 'Assessing chest expansion symmetry is an important part of respiratory assessment mainly because asymmetry can indicate:', '["Normal variation with no clinical relevance", "Unilateral pathology such as pneumothorax, large effusion, or main bronchus obstruction", "Only cardiac problems, never respiratory ones", "A permanent congenital condition in every case"]'::jsonb, 1, 'Asymmetric chest expansion is a key clinical sign that can indicate unilateral respiratory pathology such as pneumothorax, large pleural effusion, or bronchial obstruction.', 'Respiratory', '🫁', true),
(3557, 'Respiratory Scenarios', 'AI Practice Question', 'A patient''s capnography waveform shows a gradually rising baseline that never returns to zero between breaths. This is most consistent with:', '["Normal capnography", "CO2 rebreathing, possibly from an equipment issue such as an exhausted CO2 absorber or circuit problem", "Complete airway obstruction", "Successful weaning readiness"]'::jsonb, 1, 'A capnography baseline that fails to return to zero suggests CO2 rebreathing, often from equipment issues, requiring prompt troubleshooting.', 'Respiratory', '🫁', true),
(3558, 'Respiratory', 'AI Practice Question', 'Non-invasive ventilation (NIV) such as BiPAP is generally contraindicated in a patient who:', '["Has mild COPD exacerbation with good cooperation", "Has a reduced level of consciousness and cannot protect their airway", "Is able to tolerate the mask comfortably", "Has stable haemodynamics"]'::jsonb, 1, 'NIV requires the patient to cooperate and protect their own airway — reduced consciousness or inability to protect the airway is a contraindication, favouring invasive airway management instead.', 'Respiratory', '🫁', true),
(3559, 'Respiratory Scenarios', 'AI Practice Question', 'A patient on high-flow nasal cannula oxygen therapy shows improving comfort and decreasing respiratory rate over several hours. The nurse recognises the mechanism of high-flow therapy includes:', '["No physiological benefit beyond simple oxygen delivery", "Providing a small amount of positive airway pressure, washing out anatomical dead space, and delivering precisely heated/humidified high-flow oxygen", "Delivering only room air with no oxygen enrichment", "Requiring the patient to be intubated first"]'::jsonb, 1, 'High-flow nasal cannula provides some positive pressure effect, washes out nasopharyngeal dead space (improving efficiency of ventilation), and delivers heated/humidified gas at precise, high flow rates.', 'Respiratory', '🫁', true),
(3560, 'Neurology Scenarios', 'AI Practice Question', 'A patient with raised intracranial pressure is being managed with mannitol. The nurse should monitor closely for which potential complication?', '["Hypokalaemia only, with no other risk", "Dehydration and electrolyte imbalance from its osmotic diuretic effect", "Hypoglycaemia", "Bradycardia as the primary concern"]'::jsonb, 1, 'Mannitol is an osmotic diuretic used to reduce ICP — its diuretic effect requires monitoring for dehydration, electrolyte imbalance, and renal function.', 'Neurology', '🧠', true),
(3561, 'Neurology Scenarios', 'AI Practice Question', 'A patient with a severe head injury has an ICP monitor showing sustained pressures above 22mmHg despite initial measures. The care team should escalate management, which may include:', '["No further action beyond initial measures", "Further interventions such as sedation optimisation, CSF drainage, hyperosmolar therapy, or decompressive craniectomy per protocol", "Immediate discharge from ICU", "Discontinuing all monitoring"]'::jsonb, 1, 'Sustained ICP elevation despite first-line measures requires escalating tiered therapy — deeper sedation, CSF drainage, hyperosmolar agents, and potentially surgical decompression.', 'Neurology', '🧠', true),
(3562, 'Neurology', 'AI Practice Question', 'Cerebral Perfusion Pressure (CPP) is calculated as:', '["Mean Arterial Pressure minus Intracranial Pressure", "Systolic Blood Pressure plus Intracranial Pressure", "Heart Rate divided by Intracranial Pressure", "Diastolic Blood Pressure minus Heart Rate"]'::jsonb, 0, 'CPP = MAP − ICP; maintaining adequate CPP is a key goal in managing patients with raised intracranial pressure to ensure adequate cerebral blood flow.', 'Neurology', '🧠', true),
(3563, 'Neurology Scenarios', 'AI Practice Question', 'A patient with a severe traumatic brain injury has a MAP of 65mmHg and an ICP of 25mmHg. The calculated cerebral perfusion pressure is:', '["90mmHg, which is adequate", "40mmHg, which is inadequate and requires urgent intervention", "65mmHg with no relevance to ICP", "25mmHg only"]'::jsonb, 1, 'CPP = MAP − ICP = 65 − 25 = 40mmHg, below the generally accepted target range (60-70mmHg), indicating inadequate cerebral perfusion requiring urgent intervention.', 'Neurology', '🧠', true),
(3564, 'Neurology Scenarios', 'AI Practice Question', 'A patient with suspected stroke arrives within the treatment window for thrombolysis. Before administration, the nurse anticipates the priority investigation is:', '["Chest X-ray only", "Non-contrast CT brain, to exclude haemorrhage before considering thrombolysis", "ECG only, with no imaging", "Abdominal ultrasound"]'::jsonb, 1, 'A non-contrast CT brain is essential before thrombolysis to exclude haemorrhagic stroke, since thrombolytics would be dangerous/contraindicated in that setting.', 'Neurology', '🧠', true),
(3565, 'Neurology Scenarios', 'AI Practice Question', 'A patient receiving IV alteplase (thrombolytic) for acute ischaemic stroke develops a sudden severe headache and declining consciousness. The nurse should immediately suspect:', '["A normal expected side effect requiring no action", "Intracranial haemorrhage, a serious complication of thrombolysis requiring the infusion to be stopped and urgent imaging", "Improvement in the stroke symptoms", "Hypoglycaemia only"]'::jsonb, 1, 'Sudden neurological deterioration during/after thrombolysis raises urgent concern for intracranial haemorrhage — the infusion should be stopped immediately and urgent CT imaging obtained.', 'Neurology', '🧠', true),
(3566, 'Neurology', 'AI Practice Question', 'A key nursing consideration for a patient after ischaemic stroke with dysphagia is to:', '["Start normal oral diet immediately with no assessment", "Perform a formal swallow assessment before allowing oral intake, to reduce aspiration risk", "Allow the patient to eat and drink freely once awake", "Ignore swallowing ability since it always resolves quickly"]'::jsonb, 1, 'Formal swallow assessment before oral intake is essential after stroke, since undetected dysphagia significantly raises aspiration pneumonia risk.', 'Neurology', '🧠', true),
(3567, 'Neurology Scenarios', 'AI Practice Question', 'A patient develops new left-sided facial droop, arm weakness, and slurred speech that resolves completely within 20 minutes. This presentation is most consistent with:', '["A completed stroke with permanent deficit", "A Transient Ischaemic Attack (TIA), which still requires urgent evaluation given high subsequent stroke risk", "A migraine with no further evaluation needed", "Normal ageing"]'::jsonb, 1, 'Fully resolving neurological symptoms suggest TIA, which carries a significant risk of subsequent full stroke and requires urgent evaluation and secondary prevention, not reassurance.', 'Neurology', '🧠', true),
(3568, 'Neurology Scenarios', 'AI Practice Question', 'A patient with a severe traumatic brain injury requires sedation for ventilator tolerance. The team performs a ''neuro wake-up'' assessment periodically. The primary purpose of this is to:', '["Increase sedation requirements", "Allow accurate ongoing neurological assessment despite the need for sedation", "Discharge the patient sooner regardless of status", "Reduce the need for any imaging"]'::jsonb, 1, 'Periodic sedation interruption (''neuro wake-up'') allows the team to perform an accurate neurological exam, balancing the competing needs of sedation and neurological monitoring.', 'Neurology', '🧠', true),
(3569, 'Neurology Scenarios', 'AI Practice Question', 'A patient with a spinal cord injury develops sudden hypotension with warm, flushed skin below the level of injury (rather than the expected pallor). This is consistent with:', '["Hypovolaemic shock only", "Neurogenic shock, from loss of sympathetic vascular tone below the injury level", "Cardiogenic shock", "Septic shock"]'::jsonb, 1, 'Neurogenic shock from loss of sympathetic tone causes vasodilation below the injury level, producing warm, flushed skin with hypotension and often bradycardia, distinct from the cool, clammy skin of hypovolaemic shock.', 'Neurology', '🧠', true),
(3570, 'Neurology', 'AI Practice Question', 'A key nursing priority for a patient with an unstable spinal fracture before full stabilisation is:', '["Encouraging early ambulation", "Maintaining strict spinal precautions/immobilisation to prevent further cord injury during any movement or transfer", "No specific precautions are needed", "Removing the cervical collar as soon as possible for comfort"]'::jsonb, 1, 'Strict spinal precautions (log-rolling, maintaining alignment, avoiding premature collar removal) are essential to prevent further spinal cord injury until stability is confirmed.', 'Neurology', '🧠', true),
(3571, 'Neurology Scenarios', 'AI Practice Question', 'A patient with meningitis develops photophobia, neck stiffness, and a non-blanching purpuric rash. The nurse should recognise the rash as a red flag suggesting:', '["A simple allergic reaction", "Possible meningococcal sepsis, requiring urgent antibiotic administration and escalation", "A normal viral rash with no urgency", "No relationship to the meningitis diagnosis"]'::jsonb, 1, 'A non-blanching purpuric rash with meningitis symptoms is a red flag for meningococcal sepsis, a rapidly progressive, life-threatening condition requiring immediate antibiotic treatment.', 'Neurology', '🧠', true),
(3572, 'Neurology', 'AI Practice Question', 'A lumbar puncture is generally avoided or delayed in a patient with suspected meningitis if there are signs of raised intracranial pressure, primarily because of the risk of:', '["No particular risk exists in this situation", "Brain herniation from the sudden pressure change caused by CSF removal", "Improved neurological outcome", "Reduced infection risk"]'::jsonb, 1, 'Lumbar puncture in the presence of significantly raised ICP risks precipitating brain herniation due to the pressure gradient created by CSF removal — imaging is typically obtained first if raised ICP is suspected.', 'Neurology', '🧠', true),
(3573, 'Trauma Scenarios', 'AI Practice Question', 'A trauma patient''s primary survey reveals a patent airway, but breath sounds are absent on the left with visible tracheal deviation to the right and distended neck veins. The nurse should anticipate immediate:', '["Chest X-ray before any intervention", "Needle decompression of the left chest, followed by chest tube insertion", "Oral fluids", "Discharge planning"]'::jsonb, 1, 'This presentation (absent breath sounds, tracheal deviation away from the affected side, distended neck veins) indicates tension pneumothorax — needle decompression is a time-critical intervention that should not wait for imaging.', 'Burns & Trauma', '🔥', true),
(3574, 'Trauma Scenarios', 'AI Practice Question', 'A trauma patient''s secondary survey reveals a seatbelt sign across the abdomen with tenderness and guarding. The nurse should have a high index of suspicion for:', '["Simple bruising with no further concern", "Intra-abdominal organ injury requiring further imaging/evaluation", "A skin allergy", "Normal seatbelt use with no injury implications"]'::jsonb, 1, 'A seatbelt sign with abdominal tenderness/guarding raises significant concern for underlying intra-abdominal organ injury and warrants prompt further evaluation.', 'Burns & Trauma', '🔥', true),
(3575, 'Trauma Scenarios', 'AI Practice Question', 'A trauma patient has an obvious open fracture of the tibia with bone visibly protruding. The initial nursing management includes:', '["Pushing the bone back under the skin", "Covering the wound with a sterile dressing, splinting the limb in the position found, and ensuring tetanus prophylaxis is addressed", "Applying a tourniquet routinely for all fractures", "Delaying any care until the patient reaches the operating theatre"]'::jsonb, 1, 'Open fractures are managed with sterile wound covering, splinting in the position found (not reducing without guidance), and addressing infection risk including tetanus prophylaxis — bone fragments are never pushed back in.', 'Burns & Trauma', '🔥', true),
(3576, 'Trauma Scenarios', 'AI Practice Question', 'A patient with multiple trauma has a pelvic fracture suspected on examination. The nurse should avoid which action that could worsen bleeding?', '["Applying a pelvic binder as indicated", "Repeatedly ''springing'' or manually testing pelvic stability, which can dislodge clots and worsen haemorrhage", "Monitoring vital signs closely", "Preparing for possible blood transfusion"]'::jsonb, 1, 'Repeated manual pelvic stability testing (''springing'') is avoided as it can disrupt clot formation and worsen bleeding — a pelvic binder is applied instead if instability is suspected.', 'Burns & Trauma', '🔥', true),
(3577, 'Neurology', 'AI Practice Question', 'The Licox monitor, mentioned in relation to advanced neuro-monitoring, is primarily used to measure:', '["Blood glucose", "Brain tissue oxygen tension", "Cardiac output", "Urinary output"]'::jsonb, 1, 'The Licox system is a brain tissue oxygen monitor, providing direct measurement of cerebral oxygenation in severe brain injury patients.', 'Neurology', '🧠', true),
(3578, 'Neurology Scenarios', 'AI Practice Question', 'A patient with a severe brain injury is noted to have a rising temperature unrelated to infection. The nurse understands this can occur due to:', '["No relationship between brain injury and temperature regulation", "Hypothalamic dysfunction from the injury itself, sometimes called ''central fever''", "Always indicates infection with no other cause possible", "Simple dehydration only"]'::jsonb, 1, 'Severe brain injury can disrupt hypothalamic thermoregulation, causing ''central fever'' unrelated to infection, though infection must still be actively excluded.', 'Neurology', '🧠', true),
(3579, 'Shock Scenarios', 'AI Practice Question', 'A patient in septic shock has been started on noradrenaline but remains hypotensive at high doses. The team considers adding vasopressin. The rationale for adding a second-line vasopressor rather than simply escalating noradrenaline further is:', '["Vasopressin has no additional benefit", "Adding a second agent with a different mechanism can improve blood pressure control while potentially reducing the catecholamine dose and associated side effects", "Vasopressin should always replace noradrenaline entirely", "There is no rationale — a single agent is always sufficient"]'::jsonb, 1, 'Adding vasopressin (a different mechanism of action) to noradrenaline can improve haemodynamic control in refractory septic shock while potentially allowing lower catecholamine doses.', 'Shock & Haemorrhage', '⚡', true),
(3580, 'Shock Scenarios', 'AI Practice Question', 'A patient with severe sepsis has a central venous oxygen saturation (ScvO2) that is persistently low despite fluid resuscitation. This finding suggests:', '["Excellent tissue oxygen delivery relative to demand", "An imbalance between oxygen delivery and tissue oxygen demand/consumption, prompting further optimisation of resuscitation", "No clinical significance", "Complete resolution of shock"]'::jsonb, 1, 'A persistently low ScvO2 suggests inadequate oxygen delivery relative to tissue demand, prompting reassessment and further optimisation of the resuscitation strategy (fluids, haemoglobin, cardiac output).', 'Shock & Haemorrhage', '⚡', true),
(3581, 'Shock Scenarios', 'AI Practice Question', 'A trauma patient requires massive transfusion. Current evidence-based protocols typically recommend transfusing blood products in which approximate ratio?', '["Only packed red cells, with no plasma or platelets", "A balanced ratio of packed red cells, fresh frozen plasma, and platelets (e.g. approximately 1:1:1)", "Only plasma, with no red cells", "Platelets only"]'::jsonb, 1, 'Massive transfusion protocols generally use a balanced ratio (commonly around 1:1:1 of red cells, plasma, and platelets) to reduce dilutional coagulopathy and mimic whole blood replacement.', 'Shock & Haemorrhage', '⚡', true),
(3582, 'Shock Scenarios', 'AI Practice Question', 'A patient in haemorrhagic shock receives permissive hypotension resuscitation strategy prior to definitive haemorrhage control. The rationale is to:', '["Achieve completely normal blood pressure as quickly as possible regardless of ongoing bleeding", "Avoid excessively high blood pressure that could dislodge early clots and worsen bleeding before the source is controlled", "Withhold all fluids entirely", "Increase blood pressure well above normal"]'::jsonb, 1, 'Permissive hypotension (targeting a lower-than-normal blood pressure) before definitive haemorrhage control aims to avoid disrupting early clot formation, which could worsen ongoing bleeding.', 'Shock & Haemorrhage', '⚡', true),
(3583, 'Renal Scenarios', 'AI Practice Question', 'A patient''s arterial blood gas shows a metabolic acidosis with a raised anion gap in the setting of acute kidney injury. This is best explained by:', '["Loss of bicarbonate through the kidneys alone with no other cause", "Accumulation of unmeasured acids (e.g. sulfates, phosphates) that the failing kidneys cannot excrete", "Excess bicarbonate production", "No relationship between AKI and acid-base status"]'::jsonb, 1, 'AKI classically causes a high anion gap metabolic acidosis due to retention of unmeasured acid anions that the kidneys would normally excrete.', 'Renal & Fluid Balance', '💧', true),
(3584, 'Renal Scenarios', 'AI Practice Question', 'A patient with chronic kidney disease receiving erythropoietin therapy for anaemia should also have which nutrient supplemented to ensure the therapy is effective?', '["Vitamin C only", "Iron, since adequate iron stores are needed for erythropoietin to be effective", "Calcium only", "Vitamin A"]'::jsonb, 1, 'Erythropoietin stimulates red cell production, but adequate iron stores are required to support this — iron deficiency can blunt the response to erythropoietin therapy.', 'Renal & Fluid Balance', '💧', true),
(3585, 'Renal Scenarios', 'AI Practice Question', 'A patient on CRRT (Continuous Renal Replacement Therapy) develops a sudden drop in filter/circuit pressure with visible clotting in the circuit. The nurse''s priority action is to:', '["Continue therapy unchanged", "Assess anticoagulation status, notify the team, and prepare for circuit change per protocol, since a clotted circuit stops effective filtration", "Increase the blood flow rate significantly without assessment", "Disconnect the patient permanently from all renal support"]'::jsonb, 1, 'Circuit clotting on CRRT requires prompt assessment (often anticoagulation adequacy) and circuit change, since a clotted circuit is no longer providing effective renal replacement therapy.', 'Renal & Fluid Balance', '💧', true),
(3586, 'GI Scenarios', 'AI Practice Question', 'A patient with acute pancreatitis is kept nil by mouth initially, but the team plans early enteral (rather than parenteral) nutrition once tolerated. The rationale for preferring enteral nutrition here is:', '["Enteral nutrition worsens pancreatic inflammation in all cases", "Enteral nutrition helps maintain gut mucosal integrity and reduces infectious complications compared to parenteral nutrition", "Parenteral nutrition is always superior in pancreatitis", "There is no preference between the two routes"]'::jsonb, 1, 'Evidence supports early enteral nutrition in pancreatitis (via nasojejunal feeding if needed) to preserve gut integrity and reduce infectious complications, over parenteral nutrition.', 'GI, Endocrine & Metabolic', '🍽️', true),
(3587, 'GI Scenarios', 'AI Practice Question', 'A patient with severe upper GI bleeding is given a proton pump inhibitor (PPI) infusion. The rationale for this treatment is that PPIs:', '["Have no role in acute GI bleeding management", "Raise gastric pH, which stabilises clot formation and reduces rebleeding risk from peptic ulcers", "Directly stop active arterial bleeding without any other intervention", "Are used only for long-term prevention, never in acute bleeding"]'::jsonb, 1, 'PPIs raise gastric pH, which stabilises clots at the bleeding site and reduces the risk of rebleeding from peptic ulcer disease, complementing endoscopic treatment.', 'GI, Endocrine & Metabolic', '🍽️', true),
(3588, 'GI Scenarios', 'AI Practice Question', 'A patient with cirrhosis and ascites develops fever, abdominal pain, and confusion. The nurse should suspect:', '["Simple constipation", "Spontaneous bacterial peritonitis, requiring urgent assessment and ascitic fluid analysis", "A normal finding in cirrhosis with no urgency", "Only a urinary tract infection"]'::jsonb, 1, 'Fever, abdominal pain and confusion in a cirrhotic patient with ascites should raise urgent suspicion for spontaneous bacterial peritonitis, a serious infection requiring prompt diagnosis (ascitic tap) and antibiotics.', 'GI, Endocrine & Metabolic', '🍽️', true),
(3589, 'GI Scenarios', 'AI Practice Question', 'A patient with severe hyperglycaemia and altered mental status but minimal ketosis and a blood glucose of 45mmol/L is most likely experiencing:', '["Diabetic ketoacidosis (DKA)", "Hyperglycaemic Hyperosmolar State (HHS)", "Hypoglycaemia", "Normal glucose variation"]'::jsonb, 1, 'Very high glucose with altered mental status but minimal ketosis is characteristic of HHS, typically seen in type 2 diabetes, distinct from the significant ketosis of DKA.', 'GI, Endocrine & Metabolic', '🍽️', true),
(3590, 'GI Scenarios', 'AI Practice Question', 'A patient recovering from DKA treatment develops cerebral oedema, a rare but serious complication most associated with:', '["Slow, careful correction of fluids and glucose", "Overly rapid correction of hyperglycaemia and fluid shifts, particularly in paediatric patients", "No relationship to treatment rate", "Undertreatment of DKA"]'::jsonb, 1, 'Cerebral oedema, a rare but serious DKA treatment complication (especially in children), is associated with overly rapid correction of hyperglycaemia and osmotic shifts — gradual correction is recommended.', 'GI, Endocrine & Metabolic', '🍽️', true),
(3591, 'Obstetric Scenarios', 'AI Practice Question', 'A labouring woman''s fetal heart rate monitor shows repetitive late decelerations with reduced variability. This pattern is most concerning for:', '["Normal fetal sleep cycle", "Uteroplacental insufficiency/fetal hypoxia, requiring prompt intervention", "Maternal anxiety with no fetal significance", "Normal early labour finding requiring no action"]'::jsonb, 1, 'Late decelerations with reduced variability suggest uteroplacental insufficiency and possible fetal hypoxia, requiring prompt intervention (e.g. maternal repositioning, oxygen, escalation for possible urgent delivery).', 'Obstetric & Neonatal', '🤱', true),
(3592, 'Obstetric Scenarios', 'AI Practice Question', 'A woman receiving oxytocin infusion for labour augmentation develops uterine hyperstimulation (contractions too frequent/prolonged) with fetal distress. The priority nursing action is to:', '["Increase the oxytocin rate to complete labour faster", "Stop or reduce the oxytocin infusion, reposition the patient, and notify the physician immediately", "Ignore the finding since oxytocin cannot cause this", "Administer more oxytocin via a different route"]'::jsonb, 1, 'Uterine hyperstimulation with fetal distress requires stopping/reducing the oxytocin, repositioning the mother, and urgent physician notification, since ongoing hyperstimulation risks fetal hypoxia and uterine rupture.', 'Obstetric & Neonatal', '🤱', true),
(3593, 'Obstetric Scenarios', 'AI Practice Question', 'Following a shoulder dystocia delivery, the nurse should assess the newborn closely for signs of:', '["No specific concern beyond routine assessment", "Brachial plexus injury and clavicle fracture, recognised complications of shoulder dystocia", "Only skin bruising", "Congenital heart disease specifically"]'::jsonb, 1, 'Shoulder dystocia carries recognised risks of neonatal brachial plexus injury and clavicle fracture from the delivery manoeuvres required, warranting careful newborn assessment.', 'Obstetric & Neonatal', '🤱', true),
(3594, 'Obstetric Scenarios', 'AI Practice Question', 'A postpartum patient develops calf swelling, redness, and pain on day 5. The nurse should have a high index of suspicion for:', '["Normal postpartum swelling", "Deep vein thrombosis, given the elevated VTE risk in the postpartum period", "A simple muscle strain with no further evaluation needed", "Cellulitis unrelated to pregnancy"]'::jsonb, 1, 'The postpartum period carries an elevated VTE risk — unilateral calf swelling, redness and pain should raise urgent suspicion for DVT requiring prompt evaluation.', 'Obstetric & Neonatal', '🤱', true),
(3595, 'Obstetric Scenarios', 'AI Practice Question', 'A newborn is noted to have poor feeding, lethargy, temperature instability, and grunting respirations at 18 hours of age. The nurse should have a high index of suspicion for:', '["Normal newborn behaviour requiring no further assessment", "Neonatal sepsis, requiring urgent evaluation and likely empiric antibiotics", "Simple hunger, resolved with feeding alone", "Overheating from excess clothing only"]'::jsonb, 1, 'These non-specific but concerning signs in a newborn should prompt urgent evaluation for neonatal sepsis, given how rapidly it can progress and how non-specific early signs can be.', 'Obstetric & Neonatal', '🤱', true),
(3596, 'Obstetric Scenarios', 'AI Practice Question', 'A neonate with severe jaundice is started on phototherapy. The nurse should ensure:', '["The baby''s eyes are left uncovered during treatment", "Eye protection is used, the baby is adequately hydrated, and skin exposure is maximised for effective treatment", "No monitoring of bilirubin levels is needed once phototherapy starts", "The baby is kept fully clothed throughout treatment"]'::jsonb, 1, 'Phototherapy requires eye protection (to prevent retinal damage), adequate hydration, maximised skin exposure to the light, and continued bilirubin monitoring to assess treatment response.', 'Obstetric & Neonatal', '🤱', true),
(3597, 'Neonatal Scenarios', 'AI Practice Question', 'A premature infant in the NICU develops abdominal distension, bloody stools, and feeding intolerance. The nurse should suspect:', '["Normal prematurity findings requiring no evaluation", "Necrotising enterocolitis (NEC), a serious neonatal GI emergency", "Simple constipation", "Normal digestion in preterm infants"]'::jsonb, 1, 'Abdominal distension, bloody stools and feeding intolerance in a premature infant are classic signs of necrotising enterocolitis, a serious and potentially life-threatening condition requiring urgent evaluation.', 'Obstetric & Neonatal', '🤱', true),
(3598, 'Neonatal Scenarios', 'AI Practice Question', 'A neonate is diagnosed with respiratory distress syndrome and given exogenous surfactant. The rationale for this treatment is that surfactant:', '["Increases surface tension in the alveoli", "Reduces alveolar surface tension, preventing alveolar collapse and improving lung compliance", "Has no effect on lung mechanics", "Is only used to treat infection"]'::jsonb, 1, 'Surfactant reduces alveolar surface tension, preventing alveolar collapse at end-expiration and improving lung compliance — deficiency of natural surfactant is the underlying cause of RDS in premature infants.', 'Obstetric & Neonatal', '🤱', true),
(3599, 'Infection Prevention Scenarios', 'AI Practice Question', 'A patient with an infected surgical wound has cultures growing Pseudomonas aeruginosa resistant to multiple antibiotics. The nurse should anticipate:', '["Standard precautions alone are sufficient with no additional measures", "Contact precautions in addition to standard precautions, given the multidrug-resistant organism", "No precautions are necessary since it is only a wound infection", "Airborne precautions specifically"]'::jsonb, 1, 'Multidrug-resistant organisms typically require contact precautions (gown/gloves) in addition to standard precautions to prevent transmission to other patients.', 'Infection Prevention', '🦠', true),
(3600, 'Infection Prevention Scenarios', 'AI Practice Question', 'A healthcare worker sustains a needlestick injury from a used needle while caring for a patient with unknown bloodborne infection status. The immediate priority action is to:', '["Ignore the injury if it seems minor", "Wash the area thoroughly, report the incident immediately per occupational health protocol, and initiate post-exposure risk assessment", "Wait several days before reporting", "Apply a bandage only with no further action"]'::jsonb, 1, 'Needlestick injuries require immediate washing of the site, prompt reporting through occupational health channels, and timely risk assessment/post-exposure prophylaxis consideration as indicated.', 'Infection Prevention', '🦠', true),
(3601, 'Infection Prevention Scenarios', 'AI Practice Question', 'An outbreak of a highly contagious pathogen is suspected on a ward. The infection control team''s initial priority actions typically include:', '["Ignoring the situation until multiple confirmed cases occur", "Case identification, appropriate isolation of affected patients, and epidemiological investigation to identify the source and prevent further spread", "Closing the entire hospital immediately with no investigation", "Discharging all patients on the ward regardless of clinical status"]'::jsonb, 1, 'Outbreak management begins with case identification, prompt isolation of affected patients, and epidemiological investigation to trace and control the source of transmission.', 'Infection Prevention', '🦠', true),
(3602, 'Infection Prevention', 'AI Practice Question', 'The ''chain of infection'' concept includes which of the following links?', '["Only the pathogen itself, with no other factors", "Infectious agent, reservoir, portal of exit, mode of transmission, portal of entry, and susceptible host", "Only the susceptible host", "Only the mode of transmission"]'::jsonb, 1, 'The chain of infection comprises six links: infectious agent, reservoir, portal of exit, mode of transmission, portal of entry, and susceptible host — breaking any link can prevent transmission.', 'Infection Prevention', '🦠', true),
(3603, 'Pharmacology Scenarios', 'AI Practice Question', 'A patient on a heparin infusion for pulmonary embolism needs an urgent invasive procedure. The nurse anticipates the infusion will likely be:', '["Continued unchanged with no consideration of bleeding risk", "Temporarily stopped/adjusted before the procedure, given heparin''s short half-life allows relatively rapid reversal of effect", "Increased before the procedure", "Switched to an oral agent immediately with no transition plan"]'::jsonb, 1, 'Heparin''s relatively short half-life makes it practical to pause before invasive procedures to reduce bleeding risk, with anticoagulation resumed afterward as clinically appropriate.', 'ICU Pharmacology', '💊', true),
(3604, 'Pharmacology Scenarios', 'AI Practice Question', 'A patient with severe hyperkalaemia is given IV calcium gluconate as part of emergency treatment. The primary purpose of calcium gluconate in this context is to:', '["Lower serum potassium directly", "Stabilise the cardiac cell membrane, reducing arrhythmia risk, though it does NOT lower serum potassium", "Increase serum potassium further", "Treat the underlying cause of hyperkalaemia"]'::jsonb, 1, 'Calcium gluconate stabilises the myocardial membrane against the arrhythmogenic effects of hyperkalaemia — it does not actually lower the potassium level, which requires other measures like insulin/dextrose or dialysis.', 'ICU Pharmacology', '💊', true),
(3605, 'Pharmacology Scenarios', 'AI Practice Question', 'A patient receiving insulin and dextrose for hyperkalaemia treatment should be monitored closely for:', '["Hyperglycaemia only, with no other risk", "Hypoglycaemia, since insulin lowers blood glucose alongside shifting potassium intracellularly", "No monitoring is required", "Only monitor for hypertension"]'::jsonb, 1, 'Insulin/dextrose therapy for hyperkalaemia shifts potassium into cells but also lowers blood glucose — hypoglycaemia is a recognised risk requiring close glucose monitoring.', 'ICU Pharmacology', '💊', true),
(3606, 'Pharmacology Scenarios', 'AI Practice Question', 'A patient on long-term diuretic therapy develops muscle weakness, cramping, and an irregular pulse. The nurse should suspect an electrolyte disturbance, most likely:', '["Hypercalcaemia", "Hypokalaemia", "Hyperglycaemia", "Hypernatraemia"]'::jsonb, 1, 'Muscle weakness, cramping and arrhythmia in a patient on diuretics (especially loop/thiazide) are classic signs of hypokalaemia, a common diuretic side effect.', 'ICU Pharmacology', '💊', true),
(3607, 'Pharmacology Scenarios', 'AI Practice Question', 'A patient is prescribed an ACE inhibitor for hypertension. The nurse should monitor for which characteristic side effect?', '["Persistent dry cough", "Significant weight gain only", "Hair loss", "Improved potassium excretion with no monitoring needed"]'::jsonb, 0, 'ACE inhibitors are classically associated with a persistent dry cough (related to bradykinin accumulation), a common reason for switching to an ARB if troublesome.', 'ICU Pharmacology', '💊', true),
(3608, 'Pharmacology Scenarios', 'AI Practice Question', 'A patient develops serotonin syndrome after being started on two serotonergic medications simultaneously. The nurse should recognise this presentation includes:', '["Bradycardia and hypotension with no other findings", "Agitation, hyperthermia, tremor, and autonomic instability", "No clinical significance requiring only observation", "Improved mental status"]'::jsonb, 1, 'Serotonin syndrome presents with agitation, hyperthermia, neuromuscular abnormalities (tremor, clonus) and autonomic instability, requiring prompt recognition and discontinuation of the causative agents.', 'ICU Pharmacology', '💊', true),
(3609, 'Ethico-Legal Scenarios', 'AI Practice Question', 'A nurse is asked to administer a medication dose that seems unusually high compared to standard practice. The most appropriate action is to:', '["Administer it anyway, trusting the prescriber completely without question", "Verify the order, question the prescriber if uncertain, and refuse to administer until the concern is resolved", "Give half the dose without informing anyone", "Ignore the concern to avoid seeming difficult"]'::jsonb, 1, 'Nurses have both an ethical and legal responsibility to verify unusual orders and question prescribers when something seems incorrect — administering a clearly questionable dose without clarification could constitute negligence.', 'Ethics, Law & Management', '⚖️', true),
(3610, 'Ethico-Legal Scenarios', 'AI Practice Question', 'A terminally ill patient with capacity requests that all further aggressive treatment be stopped in favour of comfort care only. The nurse''s role is to:', '["Override the patient''s wishes and continue aggressive treatment regardless", "Support and advocate for the patient''s autonomous decision, ensuring the care team and family understand and respect this choice", "Refuse to provide any further care of any kind", "Ignore the request entirely"]'::jsonb, 1, 'A capacitated patient''s decision to shift focus to comfort care must be respected and supported — the nurse advocates for this autonomous decision while ensuring understanding across the care team and family.', 'Ethics, Law & Management', '⚖️', true),
(3611, 'Ethico-Legal Scenarios', 'AI Practice Question', 'A nurse witnesses a colleague falsifying a patient''s vital sign documentation. The most appropriate action is to:', '["Say nothing to preserve workplace harmony", "Address the concern directly and report it through appropriate professional/institutional channels, since falsification compromises patient safety and violates professional standards", "Falsify the same documentation to match", "Confront the colleague publicly in front of patients"]'::jsonb, 1, 'Falsifying documentation is a serious professional and patient safety violation that must be reported through appropriate channels — silence would make the observing nurse complicit.', 'Ethics, Law & Management', '⚖️', true),
(3612, 'Management Scenarios', 'AI Practice Question', 'A unit is experiencing chronic understaffing, affecting patient safety. As part of the nurse manager''s risk management responsibilities, the most appropriate action is to:', '["Ignore the issue since staffing is outside nursing''s control", "Formally document and escalate the staffing concern through appropriate channels, using incident reports where patient safety is affected", "Accept the situation permanently with no advocacy", "Blame individual staff members for the workload"]'::jsonb, 1, 'Chronic understaffing affecting safety should be formally documented and escalated through appropriate management/risk channels — this is a recognised part of risk management and patient advocacy.', 'Ethics, Law & Management', '⚖️', true),
(3613, 'Research Scenarios', 'AI Practice Question', 'A nursing student is designing a study to compare two wound dressing techniques. Randomly assigning patients to one technique or the other exemplifies which research design feature?', '["Observational design with no intervention", "An experimental design with randomisation, allowing stronger causal inference", "A purely qualitative approach", "A case study design"]'::jsonb, 1, 'Randomly assigning participants to different interventions is a hallmark of an experimental design, which allows for stronger causal conclusions than observational designs.', 'Research & Nursing Process', '📊', true),
(3614, 'Research', 'AI Practice Question', 'A literature review conducted before starting a new research study primarily serves to:', '["Have no real purpose in the research process", "Identify existing knowledge, gaps, and inform the research question/design", "Replace the need for data collection", "Serve only as a formality with no scientific value"]'::jsonb, 1, 'A literature review establishes what is already known, identifies gaps in existing knowledge, and helps refine and justify the research question and design.', 'Research & Nursing Process', '📊', true),
(3615, 'Research', 'AI Practice Question', 'A study''s ''sample'' refers to:', '["The entire population being studied", "A subset of the population selected to participate in the study, ideally representative of the larger population", "Only the researchers involved", "The study''s final conclusions"]'::jsonb, 1, 'A sample is a subset of the target population selected for study, ideally representative enough that findings can be generalised to the broader population.', 'Research & Nursing Process', '📊', true),
(3616, 'Nursing Process Scenarios', 'AI Practice Question', 'A nurse formulates the nursing diagnosis ''Risk for infection related to invasive lines'' for a critically ill patient. This is an example of which type of nursing diagnosis?', '["An actual nursing diagnosis, describing a current problem", "A risk nursing diagnosis, describing vulnerability to a potential problem rather than a current one", "A wellness diagnosis", "Not a valid nursing diagnosis format"]'::jsonb, 1, 'A ''risk for'' diagnosis identifies vulnerability to a potential future problem (based on risk factors present) rather than describing a problem the patient currently has.', 'Research & Nursing Process', '📊', true),
(3617, 'Anaesthesia Scenarios (CCN 415)', 'AI Practice Question', 'A patient scheduled for elective surgery reports a family history of a relative who died during anaesthesia from very high fever and muscle rigidity. The anaesthetic team should consider this history significant for the risk of:', '["No relevance to the current patient", "Malignant hyperthermia, a potentially inherited susceptibility requiring special anaesthetic precautions", "A simple coincidence with no genetic link", "Only relevant to cardiac risk"]'::jsonb, 1, 'Malignant hyperthermia susceptibility can be inherited — a family history of an anaesthesia-related death from hyperthermia/rigidity should prompt special precautions (e.g. avoiding trigger agents) for related patients.', 'Anaesthesia & Perioperative Care', '💉', true),
(3618, 'Anaesthesia Scenarios (CCN 415)', 'AI Practice Question', 'A patient under spinal anaesthesia for a caesarean section develops sudden hypotension and nausea. The nurse should recognise this as likely due to:', '["An allergic reaction requiring adrenaline", "Sympathetic blockade from the spinal anaesthesia causing vasodilation, typically managed with fluids and/or vasopressors", "A sign of successful anaesthesia with no action needed", "Unrelated cardiac disease"]'::jsonb, 1, 'Spinal anaesthesia blocks sympathetic tone, commonly causing vasodilation and hypotension — managed with IV fluids and vasopressors (e.g. phenylephrine/ephedrine) as needed.', 'Anaesthesia & Perioperative Care', '💉', true),
(3619, 'Anaesthesia (CCN 415)', 'AI Practice Question', 'The primary purpose of pre-anaesthetic fasting guidelines (e.g. clear fluids stopped 2 hours before surgery, solids longer) is to:', '["Improve the patient''s comfort with no other purpose", "Reduce the risk of pulmonary aspiration of gastric contents during induction of anaesthesia", "Reduce hospital costs", "Improve wound healing"]'::jsonb, 1, 'Fasting guidelines minimise gastric volume before anaesthesia to reduce the risk of aspiration during induction, when airway protective reflexes are lost.', 'Anaesthesia & Perioperative Care', '💉', true),
(3620, 'Radiology Scenarios (CCN 427)', 'AI Practice Question', 'A patient with a suspected small bowel obstruction has a CT scan with oral contrast ordered. The nurse understands the choice of a water-soluble (rather than barium) contrast agent in this context is because:', '["Water-soluble contrast is always cheaper", "If perforation is present, water-soluble contrast is safer than barium, which causes severe chemical peritonitis if it leaks into the peritoneum", "Barium provides better image quality in every situation", "There is no difference in safety between the two agents"]'::jsonb, 1, 'Water-soluble contrast is preferred when perforation is a possibility, since barium leaking into the peritoneal cavity causes severe, often fatal chemical peritonitis.', 'Radiology & Imaging', '🩻', true),
(3621, 'Radiology (CCN 427)', 'AI Practice Question', 'On an abdominal X-ray, a ''coffee bean sign'' is classically associated with which condition?', '["Simple constipation", "Sigmoid volvulus", "Normal bowel gas pattern", "Gallstones"]'::jsonb, 1, 'The ''coffee bean sign'' describes the characteristic dilated, twisted loop of bowel seen on abdominal X-ray in sigmoid volvulus.', 'Radiology & Imaging', '🩻', true),
(3622, 'Lab Sciences Scenarios (CCN 426)', 'AI Practice Question', 'A patient''s blood culture grows a common skin organism (coagulase-negative Staphylococcus) from only one of two culture sets drawn. The nurse understands this pattern often suggests:', '["Definite true bacteraemia requiring immediate aggressive treatment with no further consideration", "Possible contamination, requiring clinical correlation rather than automatic treatment", "A laboratory error with no clinical relevance", "Always indicates central line infection"]'::jsonb, 1, 'A single positive culture for a common skin contaminant (like coagulase-negative Staph) out of multiple sets often suggests contamination rather than true infection, requiring clinical correlation before treatment decisions.', 'Laboratory Sciences & Haematology', '🔬', true),
(3623, 'Lab Sciences (CCN 426)', 'AI Practice Question', 'A patient''s white blood cell count is significantly elevated with a ''left shift'' (increased immature neutrophils/bands) on the differential. This finding most strongly suggests:', '["Viral infection specifically", "An acute bacterial infection/inflammatory process", "Normal healthy findings", "Anaemia"]'::jsonb, 1, 'Leukocytosis with a left shift (increased band forms/immature neutrophils) is a classic laboratory sign of an acute bacterial infection or significant inflammatory process.', 'Laboratory Sciences & Haematology', '🔬', true),
(3624, 'ICT Scenarios', 'AI Practice Question', 'A nurse notices that a bedside monitor is displaying data that doesn''t match the patient''s clinical appearance. Before assuming a critical clinical event, the nurse should first:', '["Immediately call a cardiac arrest regardless of the patient''s appearance", "Assess the patient directly and check for technical/equipment issues (e.g. lead placement, probe position) alongside the clinical picture", "Ignore the monitor entirely from now on", "Turn off the monitor''s alarms"]'::jsonb, 1, 'Discrepancy between monitor data and clinical appearance should prompt direct patient assessment alongside checking for technical causes — always treat the patient, not just the monitor, but don''t dismiss possible true findings either.', 'Nursing Informatics & ICT', '💻', true),
(3625, 'Physiotherapy Scenarios (CCN 425)', 'AI Practice Question', 'A ventilated patient develops signs of ICU-acquired weakness. Which finding would be characteristic of this condition?', '["Isolated facial weakness with normal limb strength", "Symmetric limb weakness, typically sparing facial/ocular muscles, developing over the course of the ICU admission", "Sudden onset unilateral weakness", "No relationship to duration of critical illness"]'::jsonb, 1, 'ICU-acquired weakness typically causes symmetric limb (and often respiratory muscle) weakness that spares facial/ocular muscles, developing gradually over the course of critical illness — distinct from a sudden focal neurological event.', 'Rehabilitation & Mobilization', '🏃', true),
(3626, 'Anatomy & Physiology Scenarios (CCN 410)', 'AI Practice Question', 'A patient with severe burns loses significant fluid through the damaged skin. This highlights the skin''s normal physiological role in:', '["Hormone production only", "Fluid/temperature regulation and acting as a protective barrier against fluid loss and infection", "Filtering blood", "Producing red blood cells"]'::jsonb, 1, 'The skin normally acts as a critical barrier preventing fluid loss and infection while helping regulate temperature — extensive burn injury disrupts these functions, causing massive fluid loss.', 'Anatomy & Physiology', '🧬', true),
(3627, 'Disaster Nursing Scenarios', 'AI Practice Question', 'During a hospital''s response to a chemical exposure incident, contaminated patients arriving at the emergency department should first undergo:', '["Immediate transfer to the general ward with no other action", "Decontamination in a designated area before entering the main clinical area, to protect staff and prevent spreading contamination", "No special handling is required", "Discharge home for self-decontamination"]'::jsonb, 1, 'Decontamination in a designated area before entry to the main clinical space is essential to protect healthcare workers and prevent secondary contamination of the facility.', 'Disaster & Emergency Nursing', '🚨', true),
(3628, 'Burns & Trauma Scenarios', 'AI Practice Question', 'A patient with circumferential full-thickness burns to a limb develops absent distal pulses and severe pain. The team considers an escharotomy. The purpose of this procedure is to:', '["Provide cosmetic improvement only", "Relieve pressure from the constricting, non-elastic burned tissue (eschar) that is compromising circulation", "Prevent infection exclusively", "Reduce pain with no effect on circulation"]'::jsonb, 1, 'Escharotomy involves incising the non-elastic burned tissue to relieve the compartment-syndrome-like pressure it creates, restoring circulation to the compromised limb.', 'Burns & Trauma', '🔥', true),
(3629, 'Burns & Trauma Scenarios', 'AI Practice Question', 'A patient with major burns is assessed to be at high risk of infection during the acute phase primarily because:', '["Burns have no effect on infection risk", "Loss of the skin''s protective barrier function combined with a degree of immune suppression significantly increases infection susceptibility", "Burns always improve immune function", "Only electrical burns carry infection risk"]'::jsonb, 1, 'Major burns disrupt the skin''s protective barrier and are associated with a degree of immune suppression, both significantly increasing susceptibility to infection.', 'Burns & Trauma', '🔥', true),
(3630, 'Mixed Revision Scenarios', 'AI Practice Question', 'A nurse must decide whether to accept a verbal order for a high-risk medication during an emergency. The safest practice is to:', '["Never accept verbal orders under any circumstance, even in emergencies", "Accept the verbal order if permitted by policy during genuine emergencies, then have it read back for confirmation and documented/co-signed promptly per protocol", "Accept it and document it whenever convenient, with no read-back", "Refuse all verbal orders even during a cardiac arrest"]'::jsonb, 1, 'Verbal orders in genuine emergencies are accepted per institutional policy, with a read-back confirmation and prompt documentation/co-signature to ensure accuracy and legal compliance.', 'Mixed Revision', '📚', true),
(3631, 'Mixed Revision Scenarios', 'AI Practice Question', 'A patient''s family asks the nurse for a detailed explanation of the patient''s specific diagnosis and treatment plan. The most appropriate nursing response is to:', '["Provide the full detailed medical explanation independently, as if a physician", "Provide general supportive information within the nursing scope, and involve the physician for detailed diagnosis/treatment plan discussions", "Refuse to speak with the family at all", "Give inaccurate information rather than admit uncertainty"]'::jsonb, 1, 'Nurses provide supportive information within their scope of practice, while detailed diagnostic and treatment plan discussions are appropriately directed to the physician/medical team.', 'Mixed Revision', '📚', true),
(3632, 'Cardiovascular Scenarios', 'AI Practice Question', 'A patient with a newly inserted temporary transvenous pacemaker shows pacer spikes with no captured QRS complex at times, worsening when the patient takes a deep breath. This is most likely due to:', '["Normal pacemaker function with no concern", "Lead micro-displacement affecting capture with patient movement/position change, requiring evaluation", "Battery failure only", "Improved lead contact"]'::jsonb, 1, 'Positional variation in capture suggests possible lead micro-displacement, which can worsen with movement/breathing — this requires prompt evaluation and possible repositioning.', 'Cardiovascular', '🫀', true),
(3633, 'Cardiovascular Scenarios', 'AI Practice Question', 'A patient with acute pulmonary oedema is started on IV furosemide and nitroglycerin. The combined rationale for these two drugs is to:', '["Increase circulating volume and preload", "Reduce preload (venodilation, diuresis) to relieve pulmonary congestion", "Increase heart rate significantly", "Treat an underlying infection"]'::jsonb, 1, 'Furosemide (diuresis) and nitroglycerin (venodilation) both reduce preload, helping relieve pulmonary congestion in acute heart failure/pulmonary oedema.', 'Cardiovascular', '🫀', true),
(3634, 'Cardiovascular', 'AI Practice Question', 'A ''gallop rhythm'' on cardiac auscultation refers to the presence of:', '["A regular rhythm with no extra sounds", "An extra heart sound (S3 or S4) creating a three-beat cadence resembling a horse''s gallop", "An absent heart sound", "A murmur only, with no extra beat"]'::jsonb, 1, 'A gallop rhythm describes the cadence created by an extra heart sound (S3 or S4) added to the normal S1-S2, often associated with heart failure or reduced ventricular compliance.', 'Cardiovascular', '🫀', true),
(3635, 'Cardiovascular Scenarios', 'AI Practice Question', 'A patient with suspected right ventricular infarction (in addition to inferior MI) should generally avoid which medication class, since it can cause profound hypotension in this setting?', '["Aspirin", "Nitrates, since right ventricular infarction is preload-dependent", "Beta-blockers only", "Statins"]'::jsonb, 1, 'Right ventricular infarction makes cardiac output heavily preload-dependent — nitrates (which reduce preload) can cause severe hypotension and should generally be avoided or used with extreme caution.', 'Cardiovascular', '🫀', true),
(3636, 'Respiratory Scenarios', 'AI Practice Question', 'A patient with pulmonary fibrosis has restrictive lung disease. On spirometry, the nurse would expect:', '["Reduced FEV1 with a normal or increased FEV1/FVC ratio, and reduced total lung capacity", "Increased total lung capacity with a low FEV1/FVC ratio", "Normal spirometry results in all cases", "Increased FVC with normal FEV1"]'::jsonb, 0, 'Restrictive lung disease reduces lung volumes proportionally, typically preserving or increasing the FEV1/FVC ratio while total lung capacity and FVC are reduced — the opposite pattern to obstructive disease.', 'Respiratory', '🫁', true),
(3637, 'Respiratory Scenarios', 'AI Practice Question', 'A patient with obstructive lung disease (e.g. COPD) would typically show on spirometry:', '["Reduced FEV1/FVC ratio, reflecting airflow limitation", "Normal or increased FEV1/FVC ratio", "No measurable change from normal", "Increased FEV1 with normal FVC"]'::jsonb, 0, 'Obstructive lung disease reduces airflow, lowering FEV1 disproportionately to FVC, resulting in a reduced FEV1/FVC ratio.', 'Respiratory', '🫁', true),
(3638, 'Respiratory Scenarios', 'AI Practice Question', 'A patient''s chest X-ray shows a ''ground glass'' appearance bilaterally with worsening hypoxaemia following a recent large-volume blood transfusion. The nurse should consider:', '["Normal expected finding after transfusion", "Transfusion-Related Acute Lung Injury (TRALI), a serious transfusion complication", "Simple volume overload with no other cause needed", "No further evaluation necessary"]'::jsonb, 1, 'New bilateral pulmonary infiltrates with hypoxaemia within hours of transfusion should raise suspicion for TRALI, a serious and potentially fatal transfusion reaction requiring prompt recognition and supportive care.', 'Respiratory', '🫁', true),
(3639, 'Respiratory', 'AI Practice Question', 'Kussmaul respiration — deep, rapid breathing — is a compensatory pattern most associated with:', '["Metabolic acidosis", "Respiratory acidosis", "Metabolic alkalosis exclusively", "Normal resting breathing"]'::jsonb, 0, 'Kussmaul respirations are the body''s compensatory response to metabolic acidosis (classically DKA), blowing off CO2 to help correct the pH.', 'Respiratory', '🫁', true),
(3640, 'Neurology Scenarios', 'AI Practice Question', 'A patient with a suspected basilar skull fracture shows bruising around both eyes (''raccoon eyes'') and behind the ears (Battle''s sign). The nurse should avoid which procedure without extreme caution?', '["Oral temperature measurement", "Nasogastric tube insertion, given the risk of intracranial passage through a skull base fracture", "Peripheral IV insertion", "Blood pressure measurement"]'::jsonb, 1, 'With a suspected basilar skull fracture, blind nasogastric tube insertion risks passing through the fracture into the cranial cavity — an orogastric route is used instead if gastric access is needed.', 'Neurology', '🧠', true),
(3641, 'Neurology Scenarios', 'AI Practice Question', 'A patient with clear fluid draining from the nose after head trauma should be assessed for:', '["Simple allergic rhinitis with no further concern", "Cerebrospinal fluid rhinorrhoea, a sign of possible skull base fracture with dural tear", "A common cold unrelated to the trauma", "No clinical significance"]'::jsonb, 1, 'Clear fluid drainage from the nose after head trauma raises concern for CSF rhinorrhoea from a skull base fracture with dural tear, which can be confirmed with specific testing (e.g. halo sign, beta-2 transferrin).', 'Neurology', '🧠', true),
(3642, 'Burns Scenarios', 'AI Practice Question', 'A burns patient''s wound care plan includes silver sulfadiazine cream. The nurse understands this agent is used primarily for its:', '["Analgesic properties only", "Broad-spectrum antimicrobial effect, helping prevent burn wound infection", "Ability to promote scar-free healing with no infection benefit", "Cooling effect only"]'::jsonb, 1, 'Silver sulfadiazine is a topical antimicrobial agent commonly used in burn wound care to reduce the risk of infection.', 'Burns & Trauma', '🔥', true),
(3643, 'Renal Scenarios', 'AI Practice Question', 'A patient with rhabdomyolysis from prolonged immobility (e.g. after a fall with a long lie) is at risk of acute kidney injury. The initial management priority is:', '["Fluid restriction", "Aggressive IV fluid resuscitation to maintain good urine output and reduce myoglobin-related renal tubular injury", "Immediate dialysis in every case regardless of severity", "Withholding all fluids until creatinine normalises"]'::jsonb, 1, 'Aggressive IV fluid resuscitation to maintain good urine output is the cornerstone of preventing/managing AKI from rhabdomyolysis-related myoglobin release.', 'Renal & Fluid Balance', '💧', true),
(3644, 'GI Scenarios', 'AI Practice Question', 'A patient with severe acute pancreatitis develops worsening hypoxaemia and bilateral pulmonary infiltrates. This complication is best explained by:', '["No relationship between pancreatitis and lung injury", "The systemic inflammatory response of severe pancreatitis triggering ARDS", "A completely unrelated pre-existing lung condition", "Improved oxygenation typically expected"]'::jsonb, 1, 'Severe pancreatitis can trigger a systemic inflammatory response severe enough to cause ARDS, a recognised and serious complication requiring close respiratory monitoring.', 'GI, Endocrine & Metabolic', '🍽️', true),
(3645, 'Mixed Revision Scenarios', 'AI Practice Question', 'A patient''s family member becomes verbally aggressive toward staff in the ICU waiting area, expressing frustration about the patient''s condition. The nurse''s most appropriate initial response is to:', '["Immediately call security with no attempt at de-escalation", "Remain calm, acknowledge their distress, use active listening and de-escalation techniques, while ensuring personal safety", "Respond with equal aggression", "Ignore the family member entirely"]'::jsonb, 1, 'De-escalation begins with calm acknowledgment of distress and active listening, while always maintaining personal safety awareness — security involvement is reserved for situations that continue to escalate or pose a safety risk.', 'Mixed Revision', '📚', true),
(3646, 'Mixed Revision Scenarios', 'AI Practice Question', 'A nurse floats to an unfamiliar ICU due to staffing shortages and is assigned a complex ventilated patient. The most appropriate first action is to:', '["Refuse the assignment entirely with no discussion", "Communicate honestly about their competency level with this patient type, request orientation/support as needed, and advocate for patient safety", "Accept the assignment silently despite feeling unprepared, saying nothing", "Provide care without seeking any support or clarification"]'::jsonb, 1, 'Honest communication about competency and requesting appropriate support/orientation protects both patient safety and professional accountability — silently struggling or outright refusing without discussion are both inappropriate extremes.', 'Mixed Revision', '📚', true),
(3647, 'Cardiovascular', 'AI Practice Question', 'A junctional rhythm on ECG is characterised by:', '["Normal P waves before every QRS", "Absent, inverted, or retrograde P waves with a narrow QRS, originating from the AV junction", "A wide, bizarre QRS with no relation to the AV node", "Only seen in healthy young athletes with no clinical relevance"]'::jsonb, 1, 'Junctional rhythms arise from the AV junction, producing a narrow QRS with absent, inverted, or retrograde P waves, as the atria are depolarised abnormally or not at all from this focus.', 'Cardiovascular', '🫀', true),
(3648, 'Cardiovascular Scenarios', 'AI Practice Question', 'A patient with symptomatic bradycardia due to sick sinus syndrome is being considered for a permanent pacemaker. The nurse understands the indication reflects:', '["A temporary condition needing no long-term device", "Chronic, symptomatic conduction system dysfunction that will not reliably self-resolve", "A condition only seen in infants", "No relationship to the cardiac conduction system"]'::jsonb, 1, 'Sick sinus syndrome reflects intrinsic, chronic sinus node dysfunction — permanent pacing is indicated when it causes symptomatic bradycardia unlikely to resolve on its own.', 'Cardiovascular', '🫀', true),
(3649, 'Respiratory Scenarios', 'AI Practice Question', 'A patient''s SpO2 reads 99% but the patient appears cyanotic, confused, and has recently been exposed to carbon monoxide. The nurse should recognise that:', '["The SpO2 reading is definitely accurate and reassuring", "Standard pulse oximetry cannot distinguish oxyhaemoglobin from carboxyhaemoglobin, so a falsely reassuring high reading is possible in CO poisoning", "Cyanosis always confirms the oximeter is broken", "No further assessment is needed given the good SpO2"]'::jsonb, 1, 'Standard pulse oximeters cannot differentiate oxyhaemoglobin from carboxyhaemoglobin, so SpO2 can read falsely normal/high in CO poisoning despite severe functional hypoxia — clinical suspicion must override a reassuring number.', 'Respiratory', '🫁', true),
(3650, 'Respiratory', 'AI Practice Question', 'A patient with a large pleural effusion undergoes therapeutic thoracentesis. As a general safety principle, fluid removal in a single session is often limited to approximately:', '["No limit at all, regardless of volume", "Around 1–1.5 litres, to reduce the risk of re-expansion pulmonary oedema", "10 litres", "Only 10ml"]'::jsonb, 1, 'Large-volume thoracentesis is generally limited (often to around 1–1.5L per session) to reduce the risk of re-expansion pulmonary oedema and hypotension.', 'Respiratory', '🫁', true),
(3651, 'Neurology Scenarios', 'AI Practice Question', 'A patient with a subarachnoid haemorrhage is prescribed nimodipine. The rationale for this medication is primarily to:', '["Lower blood pressure aggressively as the main goal", "Reduce the risk of cerebral vasospasm and secondary ischaemic injury", "Treat infection", "Reduce intracranial pressure directly"]'::jsonb, 1, 'Nimodipine, a calcium channel blocker, is used after subarachnoid haemorrhage specifically to reduce the risk of cerebral vasospasm, a major cause of secondary ischaemic injury in this condition.', 'Neurology', '🧠', true),
(3652, 'Neurology Scenarios', 'AI Practice Question', 'A patient with a subarachnoid haemorrhage develops new confusion and weakness on day 7, distinct from their baseline post-bleed status. The nurse should have a high suspicion for:', '["Normal recovery progress", "Delayed cerebral ischaemia from vasospasm, a recognised complication in the days following subarachnoid haemorrhage", "Improvement in neurological status", "An unrelated finding"]'::jsonb, 1, 'Vasospasm-related delayed cerebral ischaemia classically presents with new neurological deterioration around days 4-14 after subarachnoid haemorrhage and requires urgent evaluation and management.', 'Neurology', '🧠', true),
(3653, 'Burns Scenarios', 'AI Practice Question', 'A burns patient requires daily wound dressing changes. The nurse anticipates the need for adequate analgesia beforehand primarily because:', '["Dressing changes are painless and require no analgesia", "Burn wound care, especially debridement, is one of the most painful procedures patients endure and requires proactive, adequate pain management", "Analgesia interferes with wound healing", "Pain during dressing changes has no clinical significance"]'::jsonb, 1, 'Burn dressing changes and debridement are recognised as among the most painful procedures in medicine, requiring proactive, adequate analgesia (often including procedural sedation) rather than reactive dosing.', 'Burns & Trauma', '🔥', true),
(3654, 'Obstetric Scenarios', 'AI Practice Question', 'A pregnant trauma patient in the third trimester is being assessed. The nurse should position her:', '["Flat on her back at all times", "In a left lateral tilt position (or manually displace the uterus leftward) to avoid aortocaval compression", "Prone", "Right lateral position specifically"]'::jsonb, 1, 'Left lateral tilt (or manual uterine displacement) prevents the gravid uterus from compressing the inferior vena cava and aorta when supine, which can cause significant maternal hypotension and reduced placental perfusion.', 'Obstetric & Neonatal', '🤱', true),
(3655, 'Infection Prevention', 'AI Practice Question', 'Surgical hand antisepsis, performed before donning sterile gloves for an invasive procedure, differs from routine hand hygiene primarily in that it:', '["Uses no antiseptic agent at all", "Requires a more extended, thorough technique with an antimicrobial agent to reduce both transient and resident skin flora", "Is identical to routine hand hygiene with no distinction", "Is only required once per day regardless of procedures performed"]'::jsonb, 1, 'Surgical hand antisepsis uses a more extended technique with antimicrobial agents to reduce both transient and resident skin flora, a higher standard than routine hand hygiene before non-invasive contact.', 'Infection Prevention', '🦠', true),
(3656, 'Pharmacology Scenarios', 'AI Practice Question', 'A patient receiving total parenteral nutrition develops sudden hyperglycaemia. The nurse should anticipate:', '["No intervention is needed since TPN never affects glucose", "Blood glucose monitoring and likely insulin therapy adjustment, since TPN''s high dextrose content commonly affects glycaemic control", "Immediately stopping all nutrition permanently", "Switching to oral feeding immediately regardless of gut function"]'::jsonb, 1, 'TPN''s high dextrose content commonly causes hyperglycaemia, requiring regular blood glucose monitoring and often supplemental insulin to maintain glycaemic control.', 'ICU Pharmacology', '💊', true),
(3657, 'Ethico-Legal Scenarios', 'AI Practice Question', 'A nurse is asked to witness a patient''s signature on a surgical consent form. The nurse''s role in this process is primarily to:', '["Explain the surgical risks and benefits in full clinical detail to the patient", "Confirm the patient''s identity, witness that the signature was made voluntarily, and verify the patient appears to understand they are consenting (the surgeon/team explains procedure-specific details)", "Perform the surgery-specific counselling entirely independently", "Refuse to witness any consent form under any circumstances"]'::jsonb, 1, 'When witnessing consent, the nurse confirms identity and voluntary signing and that the patient appears to understand — detailed procedure-specific explanation remains the responsibility of the surgeon/proceduralist obtaining consent.', 'Ethics, Law & Management', '⚖️', true),
(3658, 'Research', 'AI Practice Question', 'A study finds a statistically significant but very small difference between two treatments (e.g. a 1% difference in outcome) in a very large sample. This illustrates the important distinction between:', '["Statistical significance and clinical significance/relevance", "Reliability and validity, which are unrelated concepts here", "Qualitative and quantitative research", "Ethics and methodology"]'::jsonb, 0, 'A statistically significant result (often achievable with large samples even for tiny differences) does not automatically mean the finding is clinically meaningful — this distinction is important when interpreting research.', 'Research & Nursing Process', '📊', true),
(3659, 'Mixed Revision Scenarios', 'AI Practice Question', 'A nurse caring for a dying patient in the ICU notices the family has not yet said goodbye and time is limited. The most appropriate nursing action is to:', '["Rush the family out to focus purely on technical/clinical tasks", "Facilitate a supportive environment for the family to be present, adjusting non-essential tasks where possible, while continuing appropriate comfort-focused care", "Exclude the family entirely from the room", "Ignore the emotional needs of the family completely"]'::jsonb, 1, 'Facilitating family presence and connection during end-of-life care is a core nursing responsibility, balanced with continuing appropriate comfort-focused clinical care.', 'Mixed Revision', '📚', true),
(3660, 'Mixed Revision Scenarios', 'AI Practice Question', 'A nurse is caring for a patient from a cultural background different from their own, who declines a specific standard intervention due to cultural/religious beliefs. The nurse''s most appropriate approach is to:', '["Insist that the intervention is given regardless of the patient''s beliefs", "Respect the patient''s cultural/religious beliefs, explore acceptable alternatives where possible, and involve the wider team/ethics support if there is a significant clinical conflict", "Refuse to provide any further care to the patient", "Dismiss the patient''s beliefs as irrelevant to care planning"]'::jsonb, 1, 'Culturally sensitive, patient-centred care respects a patient''s beliefs while exploring clinically acceptable alternatives, escalating to ethics support when there is a significant conflict between belief and recommended care.', 'Mixed Revision', '📚', true),
(3661, 'Mixed Revision', 'AI Practice Question', 'A ''never event'' in patient safety terminology refers to:', '["A common, expected minor error", "A serious, largely preventable patient safety incident that should never occur if established safety protocols are followed (e.g. wrong-site surgery)", "An event that always results in a lawsuit", "A normal part of routine clinical practice"]'::jsonb, 1, '''Never events'' are serious, largely preventable incidents (like wrong-site surgery or retained instruments) that should never happen when recognised safety protocols are properly followed.', 'Mixed Revision', '📚', true)
