-- CCN Council Prep Pro — practice question batch 6
-- 124 more AI-generated labeled practice questions, continuing the mixed
-- scenario+recall approach across Cardiovascular, Respiratory, Neurology/Trauma,
-- Shock/Renal/GI, Obstetric/Infection Prevention, Pharmacology/Ethics/Research, and
-- the smaller categories (Anaesthesia, Radiology, Lab Sciences, ICT, Physiotherapy,
-- Disaster Nursing, Anatomy & Physiology). source='AI Practice Question' on every row.
-- Run this once in the Supabase SQL Editor (Project -> SQL Editor -> New query).

on conflict (id) do update set topic=excluded.topic, source=excluded.source, q=excluded.q, opts=excluded.opts, ans_idx=excluded.ans_idx, exp=excluded.exp, category=excluded.category, category_icon=excluded.category_icon, is_active=true;